const query = $json.query || {};

const clusters = {
  silver:  { testId: '7719640', slo: 0.995 },
  emerald: { testId: '7719620', slo: 0.995 },
  gold:    { testId: '7719621', slo: 0.9995 },
  golddr:  { testId: '7719622', slo: 0.9995 },
  'gold-ha': { primaryCluster: 'gold', secondaryCluster: 'golddr', slo: 0.9995 },
};

const testIdToCluster = {
  '7719640': 'silver',
  '7719620': 'emerald',
  '7719621': 'gold',
  '7719622': 'golddr',
};

function sqlString(value) {
  if (value === null || value === undefined) return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
}

let cluster = query.cluster ? String(query.cluster).toLowerCase() : '';
if (!cluster && query.test_id && testIdToCluster[String(query.test_id)]) {
  cluster = testIdToCluster[String(query.test_id)];
}
if (!clusters[cluster]) cluster = 'silver';

let days = parseInt(String(query.days || '30'), 10);
if (!Number.isFinite(days) || days < 1) days = 30;
// The raw downtime writer keeps 90 days; each error-budget point needs a 30-day lookback.
if (days > 60) days = 60;

const slo = (query.slo !== undefined && String(query.slo).trim() !== '')
  ? Number(query.slo)
  : Number(clusters[cluster].slo);
const safeSlo = Number.isFinite(slo) && slo > 0 && slo < 1 ? slo : Number(clusters[cluster].slo);

const rollingDays = 30;
const rollingSeconds = rollingDays * 24 * 60 * 60;
const allowedSeconds = Math.floor(rollingSeconds * (1 - safeSlo));
const cfg = clusters[cluster];

let sql;

if (cluster === 'gold-ha') {
  const primaryCluster = sqlString(cfg.primaryCluster);
  const secondaryCluster = sqlString(cfg.secondaryCluster);
  sql = [
    'WITH params AS (',
    "  SELECT now() AS end_ts, now() - interval '" + days + " days' AS start_ts, interval '3 hours' AS step, " + allowedSeconds + '::numeric AS allowed_seconds',
    '), points AS (',
    "  SELECT generate_series(date_trunc('hour', start_ts), end_ts, step) AS bucket_ts, allowed_seconds",
    '  FROM params',
    '), overlap AS (',
    '  SELECT',
    '    p.bucket_ts,',
    '    COALESCE(SUM(CASE',
    '      WHEN primary_down.period_id IS NULL OR secondary_down.period_id IS NULL THEN 0',
    "      ELSE GREATEST(0, EXTRACT(EPOCH FROM (LEAST(primary_down.ended_at, secondary_down.ended_at, p.bucket_ts) - GREATEST(primary_down.started_at, secondary_down.started_at, p.bucket_ts - interval '30 days'))))",
    '    END), 0)::numeric AS down_seconds,',
    '    p.allowed_seconds',
    '  FROM points p',
    '  LEFT JOIN public.statuscake_downtime_periods primary_down',
    '    ON primary_down.cluster = ' + primaryCluster,
    '   AND primary_down.is_valid = true',
    '   AND primary_down.started_at < p.bucket_ts',
    "   AND primary_down.ended_at > p.bucket_ts - interval '30 days'",
    '  LEFT JOIN public.statuscake_downtime_periods secondary_down',
    '    ON secondary_down.cluster = ' + secondaryCluster,
    '   AND secondary_down.is_valid = true',
    '   AND secondary_down.started_at < p.bucket_ts',
    "   AND secondary_down.ended_at > p.bucket_ts - interval '30 days'",
    '  GROUP BY p.bucket_ts, p.allowed_seconds',
    ')',
    'SELECT',
    '  bucket_ts,',
    '  GREATEST(0, ROUND(((allowed_seconds - down_seconds) / 60)::numeric, 2)) AS value_minutes',
    'FROM overlap',
    'ORDER BY bucket_ts;'
  ].join('\n');
} else {
  const safeCluster = sqlString(cluster);
  sql = [
    'WITH params AS (',
    "  SELECT now() AS end_ts, now() - interval '" + days + " days' AS start_ts, interval '3 hours' AS step, " + allowedSeconds + '::numeric AS allowed_seconds',
    '), points AS (',
    "  SELECT generate_series(date_trunc('hour', start_ts), end_ts, step) AS bucket_ts, allowed_seconds",
    '  FROM params',
    '), downtime AS (',
    '  SELECT',
    '    p.bucket_ts,',
    '    COALESCE(SUM(CASE',
    '      WHEN d.period_id IS NULL THEN 0',
    "      ELSE GREATEST(0, EXTRACT(EPOCH FROM (LEAST(d.ended_at, p.bucket_ts) - GREATEST(d.started_at, p.bucket_ts - interval '30 days'))))",
    '    END), 0)::numeric AS down_seconds,',
    '    p.allowed_seconds',
    '  FROM points p',
    '  LEFT JOIN public.statuscake_downtime_periods d',
    '    ON d.cluster = ' + safeCluster,
    '   AND d.is_valid = true',
    '   AND d.started_at < p.bucket_ts',
    "   AND d.ended_at > p.bucket_ts - interval '30 days'",
    '  GROUP BY p.bucket_ts, p.allowed_seconds',
    ')',
    'SELECT',
    '  bucket_ts,',
    '  GREATEST(0, ROUND(((allowed_seconds - down_seconds) / 60)::numeric, 2)) AS value_minutes',
    'FROM downtime',
    'ORDER BY bucket_ts;'
  ].join('\n');
}

return [{ json: { cluster, days, slo: safeSlo, rollingDays, sql } }];

const rows = $input.all().filter((item) => item.json && item.json.bucket_ts !== undefined);

const data = rows.map((item) => {
  const rawTs = item.json.bucket_ts;
  const ts = rawTs instanceof Date
    ? rawTs.toISOString()
    : new Date(rawTs).toISOString();

  return {
    timestamp: ts,
    value: Number(item.json.value_minutes),
  };
});

return [{ json: { data } }];
